"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";

export default function LoginPage() {
  const [password, setPassword] = useState("");
  const [error, setError] = useState(false);
  const router = useRouter();

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError(false);
    const res = await fetch(`/?password=${encodeURIComponent(password)}`);
    if (res.redirected) {
      window.location.href = res.url;
    } else {
      setError(true);
    }
  }

  return (
    <div className="flex flex-1 items-center justify-center p-8">
      <form onSubmit={handleSubmit} className="flex flex-col gap-4 w-full max-w-xs">
        <h1 className="text-xl font-semibold">Distillery</h1>
        <input
          type="password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          placeholder="Password"
          className="rounded border border-zinc-700 bg-zinc-900 px-3 py-2 text-sm focus:outline-none focus:border-zinc-500"
          autoFocus
        />
        {error && <p className="text-sm text-red-400">Wrong password</p>}
        <button
          type="submit"
          className="rounded bg-zinc-100 text-zinc-900 px-3 py-2 text-sm font-medium hover:bg-zinc-300 transition-colors"
        >
          Enter
        </button>
      </form>
    </div>
  );
}
